import type { ReactNode } from 'react';
export interface DialogProps {
    /**
     * Флаг открытия модального окна.
     */
    open?: boolean;
    /**
     * Основное содержимое в центральной части модального окна.
     */
    children?: ReactNode;
    /**
     * Обрабочик закрытия модального окна.
     */
    onClose?: (event?: Event | React.MouseEvent | React.KeyboardEvent) => void;
    /**
     * Пользовательский класс
     * */
    className?: string;
    /**
     * Идентификатор компонента, в который будет смонтирован Dialog.
     * По умолчанию root.
     */
    applicationRootElement?: string;
}
